export const 起雲符 = (bi) => {
    const u = bi.u, k = 2.55;
    const X = (c) => (c - 3.75) * k;
    const Z = (r) => (r - 5.4) * k + 1.0;
    const 線 = (書, 寬 = 0.34) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.36) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.4) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    // 雨冠
    線(p => p.M(X(0.2), Z(5.65)).L(X(7.2), Z(5.58)), 0.84);
    出(p => p.M(X(0.45), Z(5.70)).L(X(0.43), Z(23.24)).C(X(0.42), Z(23.89), X(0.3), Z(24.38), X(0.12), Z(24.70)), 0.76);
    出(p => p.M(X(6.6), Z(5.70)).L(X(6.58), Z(19.52)).C(X(6.55), Z(20.49), X(6.0), Z(20.81), X(5.75), Z(20.33)), 0.76);
    線(p => p.M(X(1.0), Z(6.40)).L(X(2.8), Z(6.36)), 0.57);
    線(p => p.M(X(1.0), Z(7.00)).L(X(2.8), Z(6.96)), 0.57);
    線(p => p.M(X(1.0), Z(7.60)).L(X(2.8), Z(7.56)), 0.57);
    線(p => p.M(X(4.0), Z(6.40)).C(X(4.90), Z(6.22), X(5.40), Z(6.30), X(5.8), Z(6.45)), 0.57);
    線(p => p.M(X(4.0), Z(7.00)).C(X(4.90), Z(6.82), X(5.40), Z(6.90), X(5.8), Z(7.05)), 0.57);
    線(p => p.M(X(4.0), Z(7.60)).C(X(4.90), Z(7.42), X(5.40), Z(7.50), X(5.8), Z(7.65)), 0.57);
    線(p => p.M(X(3.5), Z(5.75)).L(X(3.48), Z(8.30)), 0.72);
    // 二橫右乙＋亐長波
    線(p => p.M(X(1.5), Z(8.66)).L(X(5.4), Z(8.56)), 0.65);
    線(p => p.M(X(1.6), Z(9.96)).L(X(5.3), Z(9.86)), 0.65);
    線(p => p.M(X(5.35), Z(8.66)).C(X(6.1), Z(9.15), X(6.1), Z(10.28), X(5.4), Z(10.77)), 0.65);
    出(p => p.M(X(1.5), Z(11.90)).C(X(3.0), Z(11.42), X(4.5), Z(12.39), X(5.8), Z(11.74)), 0.68);
    // 田男框曲
    線(p => p.M(X(2.3), Z(13.52)).L(X(2.3), Z(16.76)).L(X(5.2), Z(16.68)).L(X(5.2), Z(13.44)).L(X(2.25), Z(13.52)), 0.65);
    線(p => p.M(X(3.75), Z(13.60)).L(X(3.73), Z(16.68)), 0.61);
    線(p => p.M(X(2.4), Z(15.14)).L(X(5.1), Z(15.08)), 0.61);
    出(p => p.M(X(5.2), Z(16.76)).C(X(5.5), Z(17.57), X(5.3), Z(18.22), X(4.9), Z(18.46)), 0.65);
    // 雙 S 垂繐
    出(p => p.M(X(2.9), Z(16.92)).C(X(2.4), Z(18.22), X(3.2), Z(19.52), X(2.7), Z(20.97)).C(X(2.3), Z(22.11), X(2.9), Z(23.08), X(2.75), Z(24.05)), 0.68);
    出(p => p.M(X(4.1), Z(16.92)).C(X(3.7), Z(18.38), X(4.4), Z(19.68), X(3.95), Z(21.14)).C(X(3.6), Z(22.27), X(4.15), Z(23.24), X(4.0), Z(24.21)), 0.68);
    點(3.4, 25.43);
};
